SELECT COUNT(*) AS days_above_30
FROM seattle_weather
WHERE temp_max > 30;

SELECT AVG(CASE WHEN weather = 'sun' THEN 1.0 ELSE 0.0 END) * 100 AS sunny_percentage
FROM seattle_weather
WHERE date_part('month', date) IN (6, 7, 8);

SELECT
    COUNT(CASE WHEN order_status = 'canceled' THEN 1 END) * 1.0 / COUNT(*) AS cancellation_rate
FROM olist_orders;
